def pop(self, element, strip_whitespace=1):
        if not self.elementstack:
            return
        if self.elementstack[-1][0] != element:
            return

        element, expecting_text, pieces = self.elementstack.pop()

        # Ensure each piece is a str for Python 3
        for i, v in enumerate(pieces):
            if isinstance(v, bytes):
                pieces[i] = v.decode("utf-8")

        if (
            self.version == "atom10"
            and self.contentparams.get("type", "text") == "application/xhtml+xml"
        ):
            # remove enclosing child element, but only if it is a <div> and
            # only if all the remaining content is nested underneath it.
            # This means that the divs would be retained in the following:
            #    <div>foo</div><div>bar</div>
            while pieces and len(pieces) > 1 and not pieces[-1].strip():
                del pieces[-1]
            while pieces and len(pieces) > 1 and not pieces[0].strip():
                del pieces[0]
            if (
                pieces
                and (pieces[0] == "<div>" or pieces[0].startswith("<div "))
                and pieces[-1] == "</div>"
            ):
                depth = 0
                for piece in pieces[:-1]:
                    if piece.startswith("</"):
                        depth -= 1
                        if depth == 0:
                            break
                    elif piece.startswith("<") and not piece.endswith("/>"):
                        depth += 1
                else:
                    pieces = pieces[1:-1]

        output = "".join(pieces)
        if strip_whitespace:
            output = output.strip()
        if not expecting_text:
            return output

        # decode base64 content
        if base64 and self.contentparams.get("base64", 0):
            try:
                output = base64.decodebytes(output.encode("utf8")).decode("utf8")
            except (binascii.Error, binascii.Incomplete, UnicodeDecodeError):
                pass

        # resolve relative URIs
        if (element in self.can_be_relative_uri) and output:
            # do not resolve guid elements with isPermalink="false"
            if not element == "id" or self.guidislink:
                output = self.resolve_uri(output)

        # decode entities within embedded markup
        if not self.contentparams.get("base64", 0):
            output = self.decode_entities(element, output)

        # some feed formats require consumers to guess
        # whether the content is html or plain text
        if (
            not self.version.startswith("atom")
            and self.contentparams.get("type") == "text/plain"
        ):
            if self.looks_like_html(output):
                self.contentparams["type"] = "text/html"

        # remove temporary cruft from contentparams
        try:
            del self.contentparams["mode"]
        except KeyError:
            pass
        try:
            del self.contentparams["base64"]
        except KeyError:
            pass

        is_htmlish = (
            self.map_content_type(self.contentparams.get("type", "text/html"))
            in self.html_types
        )
        # resolve relative URIs within embedded markup
        if is_htmlish and self.resolve_relative_uris:
            if element in self.can_contain_relative_uris:
                output = resolve_relative_uris(
                    output,
                    self.baseuri,
                    self.encoding,
                    self.contentparams.get("type", "text/html"),
                )

        # sanitize embedded markup
        if is_htmlish and self.sanitize_html:
            if element in self.can_contain_dangerous_markup:
                output = sanitize_html(
                    output, self.encoding, self.contentparams.get("type", "text/html")
                )

        if self.encoding and isinstance(output, bytes):
            output = output.decode(self.encoding, "ignore")

        # address common error where people take data that is already
        # utf-8, presume that it is iso-8859-1, and re-encode it.
        if self.encoding in ("utf-8", "utf-8_INVALID_PYTHON_3") and not isinstance(
            output, bytes
        ):
            try:
                output = output.encode("iso-8859-1").decode("utf-8")
            except (UnicodeEncodeError, UnicodeDecodeError):
                pass

        # map win-1252 extensions to the proper code points
        if not isinstance(output, bytes):
            output = output.translate(_cp1252)

        # categories/tags/keywords/whatever are handled in _end_category or
        # _end_tags or _end_itunes_keywords
        if element in ("category", "tags", "itunes_keywords"):
            return output

        if element == "title" and -1 < self.title_depth <= self.depth:
            return output

        # store output in appropriate place(s)
        if self.inentry and not self.insource:
            if element == "content":
                self.entries[-1].setdefault(element, [])
                contentparams = copy.deepcopy(self.contentparams)
                contentparams["value"] = output
                self.entries[-1][element].append(contentparams)
            elif element == "link":
                if not self.inimage:
                    # query variables in urls in link elements are improperly
                    # converted from `?a=1&b=2` to `?a=1&b;=2` as if they're
                    # unhandled character references. fix this special case.
                    output = output.replace("&amp;", "&")
                    output = re.sub("&([A-Za-z0-9_]+);", r"&\g<1>", output)
                    if self.isentrylink or not self.entries[-1].get(element):
                        self.entries[-1][element] = output
                    if output:
                        self.entries[-1]["links"][-1]["href"] = output
            else:
                if element == "description":
                    element = "summary"
                old_value_depth = self.property_depth_map.setdefault(
                    self.entries[-1], {}
                ).get(element)
                if old_value_depth is None or self.depth <= old_value_depth:
                    self.property_depth_map[self.entries[-1]][element] = self.depth
                    self.entries[-1][element] = output
                if self.incontent:
                    contentparams = copy.deepcopy(self.contentparams)
                    contentparams["value"] = output
                    self.entries[-1][element + "_detail"] = contentparams
        elif (
            self.infeed or self.insource
        ):  # and (not self.intextinput) and (not self.inimage):
            context = self._get_context()
            if element == "description":
                element = "subtitle"
            context[element] = output
            if element == "link":
                # fix query variables; see above for the explanation
                output = re.sub("&([A-Za-z0-9_]+);", r"&\g<1>", output)
                context[element] = output
                context["links"][-1]["href"] = output
            elif self.incontent:
                contentparams = copy.deepcopy(self.contentparams)
                contentparams["value"] = output
                context[element + "_detail"] = contentparams
        return output

def _parse_date_rfc822(date):
    """Parse RFC 822 dates and times
    http://tools.ietf.org/html/rfc822#section-5

    There are some formatting differences that are accounted for:
    1. Years may be two or four digits.
    2. The month and day can be swapped.
    3. Additional timezone names are supported.
    4. A default time and timezone are assumed if only a date is present.

    :param str date: a date/time string that will be converted to a time tuple
    :returns: a UTC time tuple, or None
    :rtype: time.struct_time | None
    """

    parts = date.lower().split()
    if len(parts) < 5:
        # Assume that the time and timezone are missing
        parts.extend(("00:00:00", "0000"))
    # Remove the day name
    if parts[0][:3] in day_names:
        # Comma without spaces:
        # 'Fri,24 Nov 2023 18:28:36 -0000'
        if "," in parts[0] and parts[0][-1] != ",":
            parts.insert(1, parts[0].rpartition(",")[2])
        parts = parts[1:]
    if len(parts) < 5:
        # If there are still fewer than five parts, there's not enough
        # information to interpret this.
        return None

    # Handle the day and month name.
    month = months.get(parts[1][:3])
    try:
        day = int(parts[0])
    except ValueError:
        # Check if the day and month are swapped.
        if months.get(parts[0][:3]):
            try:
                day = int(parts[1])
            except ValueError:
                return None
            month = months.get(parts[0][:3])
        else:
            return None
    if not month:
        return None

    # Handle the year.
    try:
        year = int(parts[2])
    except ValueError:
        return None
    # Normalize two-digit years:
    # Anything in the 90's is interpreted as 1990 and on.
    # Anything 89 or less is interpreted as 2089 or before.
    if len(parts[2]) <= 2:
        year += (1900, 2000)[year < 90]

    # Handle the time (default to 00:00:00).
    time_parts = parts[3].split(":")
    time_parts.extend(("0",) * (3 - len(time_parts)))
    try:
        (hour, minute, second) = (int(i) for i in time_parts)
    except ValueError:
        return None

    # Handle the timezone information, if any (default to +0000).
    # Strip 'Etc/' from the timezone.
    if parts[4].startswith("etc/"):
        parts[4] = parts[4][4:]
    # Normalize timezones that start with 'gmt':
    # GMT-05:00 => -0500
    # GMT => GMT
    if parts[4].startswith("gmt"):
        parts[4] = "".join(parts[4][3:].split(":")) or "gmt"
    # Handle timezones like '-0500', '+0500', and 'EST'
    if parts[4] and parts[4][0] in ("-", "+"):
        try:
            if ":" in parts[4]:
                timezone_hours = int(parts[4][1:3])
                timezone_minutes = int(parts[4][4:])
            else:
                timezone_hours = int(parts[4][1:3])
                timezone_minutes = int(parts[4][3:])
        except ValueError:
            return None
        if parts[4].startswith("-"):
            timezone_hours *= -1
            timezone_minutes *= -1
    else:
        timezone_hours = timezone_names.get(parts[4], 0)
        timezone_minutes = 0

    # Create the datetime object and timezone delta objects
    try:
        stamp = datetime.datetime(year, month, day, hour, minute, second)
    except ValueError:
        return None
    delta = datetime.timedelta(0, 0, 0, 0, timezone_minutes, timezone_hours)

    # Return the date and timestamp in a UTC 9-tuple
    try:
        return (stamp - delta).utctimetuple()
    except (OverflowError, ValueError):
        # IronPython throws ValueErrors instead of OverflowErrors
        return None

def unknown_starttag(self, tag, attrs):
        # increment depth counter
        self.depth += 1

        # normalize attrs
        attrs = [self._normalize_attributes(attr) for attr in attrs]

        # track xml:base and xml:lang
        attrs_d = dict(attrs)
        baseuri = attrs_d.get("xml:base", attrs_d.get("base")) or self.baseuri
        if isinstance(baseuri, bytes):
            baseuri = baseuri.decode(self.encoding, "ignore")
        # ensure that self.baseuri is always an absolute URI that
        # uses a whitelisted URI scheme (e.g. not `javascript:`)
        if self.baseuri:
            self.baseuri = make_safe_absolute_uri(self.baseuri, baseuri) or self.baseuri
        else:
            self.baseuri = _urljoin(self.baseuri, baseuri)
        lang = attrs_d.get("xml:lang", attrs_d.get("lang"))
        if lang == "":
            # xml:lang could be explicitly set to '', we need to capture that
            lang = None
        elif lang is None:
            # if no xml:lang is specified, use parent lang
            lang = self.lang
        if lang:
            if tag in ("feed", "rss", "rdf:RDF"):
                self.feeddata["language"] = lang.replace("_", "-")
        self.lang = lang
        self.basestack.append(self.baseuri)
        self.langstack.append(lang)

        # track namespaces
        for prefix, uri in attrs:
            if prefix.startswith("xmlns:"):
                self.track_namespace(prefix[6:], uri)
            elif prefix == "xmlns":
                self.track_namespace(None, uri)

        # track inline content
        if self.incontent and not self.contentparams.get("type", "xml").endswith("xml"):
            if tag in ("xhtml:div", "div"):
                return  # typepad does this 10/2007
            # element declared itself as escaped markup, but it isn't really
            self.contentparams["type"] = "application/xhtml+xml"
        if self.incontent and self.contentparams.get("type") == "application/xhtml+xml":
            if tag.find(":") != -1:
                prefix, tag = tag.split(":", 1)
                namespace = self.namespaces_in_use.get(prefix, "")
                if tag == "math" and namespace == "http://www.w3.org/1998/Math/MathML":
                    attrs.append(("xmlns", namespace))
                if tag == "svg" and namespace == "http://www.w3.org/2000/svg":
                    attrs.append(("xmlns", namespace))
            if tag == "svg":
                self.svgOK += 1
            return self.handle_data(f"<{tag}{self.strattrs(attrs)}>", escape=0)

        # match namespaces
        if tag.find(":") != -1:
            prefix, suffix = tag.split(":", 1)
        else:
            prefix, suffix = "", tag
        prefix = self.namespacemap.get(prefix, prefix)
        if prefix:
            prefix = prefix + "_"

        # Special hack for better tracking of empty textinput/image elements in
        # illformed feeds.
        if (not prefix) and tag not in ("title", "link", "description", "name"):
            self.intextinput = 0
        if (not prefix) and tag not in (
            "title",
            "link",
            "description",
            "url",
            "href",
            "width",
            "height",
        ):
            self.inimage = 0

        # call special handler (if defined) or default handler
        methodname = "_start_" + prefix + suffix
        try:
            method = getattr(self, methodname)
            return method(attrs_d)
        except AttributeError:
            # Since there's no handler or something has gone wrong we
            # explicitly add the element and its attributes.
            unknown_tag = prefix + suffix
            if len(attrs_d) == 0:
                # No attributes so merge it into the enclosing dictionary
                return self.push(unknown_tag, 1)
            # Has attributes so create it in its own dictionary
            context = self._get_context()
            context[unknown_tag] = attrs_d

def _parse_date_iso8601(date_string):
    """Parse a variety of ISO-8601-compatible formats like 20040105"""
    m = None
    for _iso8601_match in _iso8601_matches:
        m = _iso8601_match(date_string)
        if m:
            break
    if not m:
        return
    if m.span() == (0, 0):
        return
    params = m.groupdict()
    ordinal = params.get("ordinal", 0)
    if ordinal:
        ordinal = int(ordinal)
    else:
        ordinal = 0
    year = params.get("year", "--")
    if not year or year == "--":
        year = time.gmtime()[0]
    elif len(year) == 2:
        # ISO 8601 assumes current century, i.e. 93 -> 2093, NOT 1993
        year = 100 * int(time.gmtime()[0] / 100) + int(year)
    else:
        year = int(year)
    month = params.get("month", "-")
    if not month or month == "-":
        # ordinals are NOT normalized by mktime, we simulate them
        # by setting month=1, day=ordinal
        if ordinal:
            month = 1
        else:
            month = time.gmtime()[1]
    month = int(month)
    day = params.get("day", 0)
    if not day:
        # see above
        if ordinal:
            day = ordinal
        elif (
            params.get("century", 0) or params.get("year", 0) or params.get("month", 0)
        ):
            day = 1
        else:
            day = time.gmtime()[2]
    else:
        day = int(day)
    # special case of the century - is the first year of the 21st century
    # 2000 or 2001 ? The debate goes on...
    if "century" in params:
        year = (int(params["century"]) - 1) * 100 + 1
    # in ISO 8601 most fields are optional
    for field in ["hour", "minute", "second", "tzhour", "tzmin"]:
        if not params.get(field, None):
            params[field] = 0
    hour = int(params.get("hour", 0))
    minute = int(params.get("minute", 0))
    second = int(float(params.get("second", 0)))
    # weekday is normalized by mktime(), we can ignore it
    weekday = 0
    daylight_savings_flag = -1
    tm = [
        year,
        month,
        day,
        hour,
        minute,
        second,
        weekday,
        ordinal,
        daylight_savings_flag,
    ]
    # ISO 8601 time zone adjustments
    tz = params.get("tz")
    if tz and tz != "Z":
        if tz[0] == "-":
            tm[3] += int(params.get("tzhour", 0))
            tm[4] += int(params.get("tzmin", 0))
        elif tz[0] == "+":
            tm[3] -= int(params.get("tzhour", 0))
            tm[4] -= int(params.get("tzmin", 0))
        else:
            return None
    # Python's time.mktime() is a wrapper around the ANSI C mktime(3c)
    # which is guaranteed to normalize d/m/y/h/m/s.
    # Many implementations have bugs, but we'll pretend they don't.
    return time.localtime(time.mktime(tuple(tm)))

def _parse_date_w3dtf(datestr):
    if not datestr.strip():
        return None
    parts = datestr.lower().split("t")
    if len(parts) == 1:
        # This may be a date only, or may be an MSSQL-style date
        parts = parts[0].split()
        if len(parts) == 1:
            # Treat this as a date only
            parts.append("00:00:00z")
    elif len(parts) > 2:
        return None
    date = parts[0].split("-", 2)
    if not date or len(date[0]) != 4:
        return None
    # Ensure that `date` has 3 elements. Using '1' sets the default
    # month to January and the default day to the 1st of the month.
    date.extend(["1"] * (3 - len(date)))
    try:
        year, month, day = (int(i) for i in date)
    except ValueError:
        # `date` may have more than 3 elements or may contain
        # non-integer strings.
        return None
    if parts[1].endswith("z"):
        parts[1] = parts[1][:-1]
        parts.append("z")
    # Append the numeric timezone offset, if any, to parts.
    # If this is an MSSQL-style date then parts[2] already contains
    # the timezone information, so `append()` will not affect it.
    # Add 1 to each value so that if `find()` returns -1 it will be
    # treated as False.
    loc = parts[1].find("-") + 1 or parts[1].find("+") + 1 or len(parts[1]) + 1
    loc = loc - 1
    parts.append(parts[1][loc:])
    parts[1] = parts[1][:loc]
    time = parts[1].split(":", 2)
    # Ensure that time has 3 elements. Using '0' means that the
    # minutes and seconds, if missing, will default to 0.
    time.extend(["0"] * (3 - len(time)))
    if parts[2][:1] in ("-", "+"):
        try:
            tzhour = int(parts[2][1:3])
            tzmin = int(parts[2][4:])
        except ValueError:
            return None
        if parts[2].startswith("-"):
            tzhour = tzhour * -1
            tzmin = tzmin * -1
    else:
        tzhour = timezonenames.get(parts[2], 0)
        tzmin = 0
    try:
        hour, minute, second = (int(float(i)) for i in time)
    except ValueError:
        return None
    # Create the datetime object and timezone delta objects
    try:
        stamp = datetime.datetime(year, month, day, hour, minute, second)
    except ValueError:
        return None
    delta = datetime.timedelta(0, 0, 0, 0, tzmin, tzhour)
    # Return the date and timestamp in a UTC 9-tuple
    try:
        return (stamp - delta).utctimetuple()
    except (OverflowError, ValueError):
        # IronPython throws ValueErrors instead of OverflowErrors
        return None

def unknown_starttag(self, tag, attrs):
        acceptable_attributes = self.acceptable_attributes
        keymap = {}
        if tag not in self.acceptable_elements or self.svgOK:
            if tag in self.unacceptable_elements_with_end_tag:
                self.unacceptablestack += 1

            # add implicit namespaces to html5 inline svg/mathml
            if self._type.endswith("html"):
                if not dict(attrs).get("xmlns"):
                    if tag == "svg":
                        attrs.append(("xmlns", "http://www.w3.org/2000/svg"))
                    if tag == "math":
                        attrs.append(("xmlns", "http://www.w3.org/1998/Math/MathML"))

            # not otherwise acceptable, perhaps it is MathML or SVG?
            if (
                tag == "math"
                and ("xmlns", "http://www.w3.org/1998/Math/MathML") in attrs
            ):
                self.mathmlOK += 1
            if tag == "svg" and ("xmlns", "http://www.w3.org/2000/svg") in attrs:
                self.svgOK += 1

            # chose acceptable attributes based on tag class, else bail
            if self.mathmlOK and tag in self.mathml_elements:
                acceptable_attributes = self.mathml_attributes
            elif self.svgOK and tag in self.svg_elements:
                # For most vocabularies, lowercasing is a good idea. Many
                # svg elements, however, are camel case.
                if not self.svg_attr_map:
                    lower = [attr.lower() for attr in self.svg_attributes]
                    mix = [a for a in self.svg_attributes if a not in lower]
                    self.svg_attributes = lower
                    self.svg_attr_map = {a.lower(): a for a in mix}

                    lower = [attr.lower() for attr in self.svg_elements]
                    mix = [a for a in self.svg_elements if a not in lower]
                    self.svg_elements = lower
                    self.svg_elem_map = {a.lower(): a for a in mix}
                acceptable_attributes = self.svg_attributes
                tag = self.svg_elem_map.get(tag, tag)
                keymap = self.svg_attr_map
            elif tag not in self.acceptable_elements:
                return

        # declare xlink namespace, if needed
        if self.mathmlOK or self.svgOK:
            if any(a for a in attrs if a[0].startswith("xlink:")):
                if not ("xmlns:xlink", "http://www.w3.org/1999/xlink") in attrs:
                    attrs.append(("xmlns:xlink", "http://www.w3.org/1999/xlink"))

        clean_attrs = []
        for key, value in self.normalize_attrs(attrs):
            if key == "style" and "style" in acceptable_attributes:
                clean_value = self.sanitize_style(value)
                if clean_value:
                    clean_attrs.append((key, clean_value))
            elif key in acceptable_attributes:
                key = keymap.get(key, key)
                # make sure the uri uses an acceptable uri scheme
                if key == "href":
                    value = make_safe_absolute_uri(value)
                clean_attrs.append((key, value))
        super().unknown_starttag(tag, clean_attrs)

def __getitem__(self, key, _stacklevel=2):
        """
        :return: A :class:`FeedParserDict`.
        """

        if key == "category":
            try:
                return dict.__getitem__(self, "tags")[0]["term"]
            except IndexError:
                raise KeyError("object doesn't have key 'category'")
        elif key == "enclosures":
            return [
                FeedParserDict(
                    [(name, value) for (name, value) in link.items() if name != "rel"]
                )
                for link in dict.__getitem__(self, "links")
                if link["rel"] == "enclosure"
            ]
        elif key == "license":
            for link in dict.__getitem__(self, "links"):
                if link["rel"] == "license" and "href" in link:
                    return link["href"]
        elif key == "updated":
            # Temporarily help developers out by keeping the old
            # broken behavior that was reported in issue 310.
            # This fix was proposed in issue 328.
            if not dict.__contains__(self, "updated") and dict.__contains__(
                self, "published"
            ):
                warnings.warn(
                    "To avoid breaking existing software while "
                    "fixing issue 310, a temporary mapping has been created "
                    "from `updated` to `published` if `updated` doesn't "
                    "exist. This fallback will be removed in a future version "
                    "of feedparser.",
                    DeprecationWarning,
                    stacklevel=_stacklevel,
                )
                return dict.__getitem__(self, "published")
            return dict.__getitem__(self, "updated")
        elif key == "updated_parsed":
            if not dict.__contains__(self, "updated_parsed") and dict.__contains__(
                self, "published_parsed"
            ):
                warnings.warn(
                    "To avoid breaking existing software while "
                    "fixing issue 310, a temporary mapping has been created "
                    "from `updated_parsed` to `published_parsed` if "
                    "`updated_parsed` doesn't exist. This fallback will be "
                    "removed in a future version of feedparser.",
                    DeprecationWarning,
                    stacklevel=_stacklevel,
                )
                return dict.__getitem__(self, "published_parsed")
            return dict.__getitem__(self, "updated_parsed")
        else:
            realkey = self.keymap.get(key, key)
            if isinstance(realkey, list):
                for k in realkey:
                    if dict.__contains__(self, k):
                        return dict.__getitem__(self, k)
            elif dict.__contains__(self, realkey):
                return dict.__getitem__(self, realkey)
        return dict.__getitem__(self, key)

def startElementNS(self, name, qname, attrs):
        namespace, localname = name
        lowernamespace = str(namespace or "").lower()
        if lowernamespace.find("backend.userland.com/rss") != -1:
            # match any backend.userland.com namespace
            namespace = "http://backend.userland.com/rss"
            lowernamespace = namespace
        if qname and qname.find(":") > 0:
            givenprefix = qname.split(":")[0]
        else:
            givenprefix = None
        prefix = self._matchnamespaces.get(lowernamespace, givenprefix)
        if (
            givenprefix
            and (prefix is None or (prefix == "" and lowernamespace == ""))
            and givenprefix not in self.namespaces_in_use
        ):
            raise UndeclaredNamespace(
                "'%s' is not associated with a namespace" % givenprefix
            )
        localname = str(localname).lower()

        # qname implementation is horribly broken in Python 2.1 (it
        # doesn't report any), and slightly broken in Python 2.2 (it
        # doesn't report the xml: namespace). So we match up namespaces
        # with a known list first, and then possibly override them with
        # the qnames the SAX parser gives us (if indeed it gives us any
        # at all).  Thanks to MatejC for helping me test this and
        # tirelessly telling me that it didn't work yet.
        attrsD, self.decls = self.decls, {}
        if localname == "math" and namespace == "http://www.w3.org/1998/Math/MathML":
            attrsD["xmlns"] = namespace
        if localname == "svg" and namespace == "http://www.w3.org/2000/svg":
            attrsD["xmlns"] = namespace

        if prefix:
            localname = prefix.lower() + ":" + localname
        elif namespace and not qname:  # Expat
            for name, value in self.namespaces_in_use.items():
                if name and value == namespace:
                    localname = name + ":" + localname
                    break

        for (namespace, attrlocalname), attrvalue in attrs.items():
            lowernamespace = (namespace or "").lower()
            prefix = self._matchnamespaces.get(lowernamespace, "")
            if prefix:
                attrlocalname = prefix + ":" + attrlocalname
            attrsD[str(attrlocalname).lower()] = attrvalue
        for qname in attrs.getQNames():
            attrsD[str(qname).lower()] = attrs.getValueByQName(qname)
        localname = str(localname).lower()
        self.unknown_starttag(localname, list(attrsD.items()))

def unknown_endtag(self, tag):
        # match namespaces
        if tag.find(":") != -1:
            prefix, suffix = tag.split(":", 1)
        else:
            prefix, suffix = "", tag
        prefix = self.namespacemap.get(prefix, prefix)
        if prefix:
            prefix = prefix + "_"
        if suffix == "svg" and self.svgOK:
            self.svgOK -= 1

        # call special handler (if defined) or default handler
        methodname = "_end_" + prefix + suffix
        try:
            if self.svgOK:
                raise AttributeError()
            method = getattr(self, methodname)
            method()
        except AttributeError:
            self.pop(prefix + suffix)

        # track inline content
        if self.incontent and not self.contentparams.get("type", "xml").endswith("xml"):
            # element declared itself as escaped markup, but it isn't really
            if tag in ("xhtml:div", "div"):
                return  # typepad does this 10/2007
            self.contentparams["type"] = "application/xhtml+xml"
        if self.incontent and self.contentparams.get("type") == "application/xhtml+xml":
            tag = tag.split(":")[-1]
            self.handle_data("</%s>" % tag, escape=0)

        # track xml:base and xml:lang going out of scope
        if self.basestack:
            self.basestack.pop()
            if self.basestack and self.basestack[-1]:
                self.baseuri = self.basestack[-1]
        if self.langstack:
            self.langstack.pop()
            if self.langstack:  # and (self.langstack[-1] is not None):
                self.lang = self.langstack[-1]

        self.depth -= 1

def sanitize_style(self, style):
        # disallow urls
        style = re.compile(r"url\s*\(\s*[^\s)]+?\s*\)\s*").sub(" ", style)

        # gauntlet
        if not re.match(
            r"""^([:,;#%.\sa-zA-Z0-9!]|\w-\w|'[\s\w]+'|"[\s\w]+"|\([\d,\s]+\))*$""",
            style,
        ):
            return ""
        # This replaced a regexp that used re.match and was prone to
        # pathological back-tracking.
        if re.sub(r"\s*[-\w]+\s*:\s*[^:;]*;?", "", style).strip():
            return ""

        clean = []
        for prop, value in re.findall(r"([-\w]+)\s*:\s*([^:;]*)", style):
            if not value:
                continue
            if prop.lower() in self.acceptable_css_properties:
                clean.append(prop + ": " + value + ";")
            elif prop.split("-")[0].lower() in [
                "background",
                "border",
                "margin",
                "padding",
            ]:
                for keyword in value.split():
                    if (
                        keyword not in self.acceptable_css_keywords
                        and not self.valid_css_values.match(keyword)
                    ):
                        break
                else:
                    clean.append(prop + ": " + value + ";")
            elif self.svgOK and prop.lower() in self.acceptable_svg_properties:
                clean.append(prop + ": " + value + ";")

        return " ".join(clean)

def _sync_author_detail(self, key="author"):
        context = self._get_context()
        detail = context.get("%ss" % key, [FeedParserDict()])[-1]
        if detail:
            name = detail.get("name")
            email = detail.get("email")
            if name and email:
                context[key] = f"{name} ({email})"
            elif name:
                context[key] = name
            elif email:
                context[key] = email
        else:
            author, email = context.get(key), None
            if not author:
                return
            emailmatch = email_pattern.search(author)
            if emailmatch:
                email = emailmatch.group(0)
                # probably a better way to do the following, but it passes
                # all the tests
                author = author.replace(email, "")
                author = author.replace("()", "")
                author = author.replace("<>", "")
                author = author.replace("&lt;&gt;", "")
                author = author.strip()
                if author and (author[0] == "("):
                    author = author[1:]
                if author and (author[-1] == ")"):
                    author = author[:-1]
                author = author.strip()
            if author or email:
                context.setdefault("%s_detail" % key, detail)
            if author:
                detail["name"] = author
            if email:
                detail["email"] = email

def parse_entry(self, e):
        entry = FeedParserDict()
        for src, dst in self.ITEM_FIELDS:
            if src in e:
                entry[dst] = e[src]

        if "content_text" in e:
            entry["content"] = c = FeedParserDict()
            c["value"] = e["content_text"]
            c["type"] = "text"
        elif "content_html" in e:
            entry["content"] = c = FeedParserDict()
            c["value"] = sanitize_html(
                e["content_html"], self.encoding, "application/json"
            )
            c["type"] = "html"

        if "date_published" in e:
            entry["published"] = e["date_published"]
            entry["published_parsed"] = _parse_date(e["date_published"])
        if "date_updated" in e:
            entry["updated"] = e["date_modified"]
            entry["updated_parsed"] = _parse_date(e["date_modified"])

        if "tags" in e:
            entry["category"] = e["tags"]

        if "author" in e:
            self.parse_author(e["author"], entry)

        if "attachments" in e:
            entry["enclosures"] = [self.parse_attachment(a) for a in e["attachments"]]

        return entry

def test_convert_file_to_utf8(headers, length):
    digits = b"0123456789abcdef"
    data = feedparser.encodings.convert_to_utf8({}, b"", {}) + digits * int(
        length / len(digits) + 2
    )

    expected_result = {}
    expected_output = feedparser.encodings.convert_to_utf8(
        headers, data, expected_result
    )
    expected_result.pop("bozo_exception", None)

    actual_result = {}
    factory = feedparser.encodings.convert_file_to_utf8(
        headers, io.BytesIO(data), actual_result
    )

    assert factory.get_text_file().read() == expected_output.decode("utf-8")
    assert factory.get_binary_file().read() == expected_output

    actual_result.pop("bozo_exception", None)
    assert actual_result == expected_result

    actual_result = {}
    factory = feedparser.encodings.convert_file_to_utf8(
        headers, io.StringIO(data.decode("utf-8")), actual_result
    )

    assert factory.get_text_file().read() == expected_output.decode("utf-8")

    actual_result.pop("bozo_exception", None)
    assert actual_result == expected_result

def get_file_contents(file: str) -> tuple[bytes, str]:
    """Identify data's encoding using its byte order mark and convert it to text."""

    with open(file, "rb") as fp:
        data = fp.read()

    if data[:4] == b"\x00\x00\xfe\xff":
        return data, data.decode("utf-32be")
    elif data[:4] == b"\xff\xfe\x00\x00":
        return data, data.decode("utf-32le")
    elif data[:4] == b"\x00\x00\x00\x3c":
        return data, data.decode("utf-32be")
    elif data[:4] == b"\x3c\x00\x00\x00":
        return data, data.decode("utf-32le")
    elif data[:4] == b"\x00\x3c\x00\x3f":
        return data, data.decode("utf-16be")
    elif data[:4] == b"\x3c\x00\x3f\x00":
        return data, data.decode("utf-16le")
    elif (data[:2] == b"\xfe\xff") and (data[2:4] != b"\x00\x00"):
        return data, data[2:].decode("utf-16be")
    elif (data[:2] == b"\xff\xfe") and (data[2:4] != b"\x00\x00"):
        return data, data[2:].decode("utf-16le")
    elif data[:3] == b"\xef\xbb\xbf":
        return data, data[3:].decode("utf-8", errors="ignore")

    # No byte order mark was found. Assume UTF-8, and ignore errors.
    return data, data.decode("utf-8", errors="ignore")

def get(url: str, result: dict[str, typing.Any]) -> bytes:
    try:
        response = requests.get(
            url,
            headers={"Accept": ACCEPT_HEADER},
            timeout=10,
        )
    except requests.RequestException as exception:
        result["bozo"] = True
        result["bozo_exception"] = exception
        return b""

    # Lowercase the HTTP header keys for comparisons per RFC 2616.
    result["headers"] = {k.lower(): v for k, v in response.headers.items()}

    # save HTTP headers
    if "etag" in result["headers"]:
        result["etag"] = result["headers"]["etag"]
    if "last-modified" in result["headers"]:
        modified = result["headers"]["last-modified"]
        if modified:
            result["modified"] = modified
            result["modified_parsed"] = _parse_date(modified)
    result["href"] = response.url
    result["status"] = response.status_code
    return response.content

def read(self, size=-1):
        buffer = self.file.read(0)

        if self.offset < len(self.prefix):
            if size < 0:
                chunk = self.prefix[self.offset :]
            else:
                chunk = self.prefix[self.offset : self.offset + size]
                size -= len(chunk)
            buffer += chunk
            self.offset += len(chunk)

        while True:
            chunk = self.file.read(size)
            if not chunk:
                break
            buffer += chunk
            self.offset += len(chunk)

            if size <= 0:
                break

            size -= len(chunk)

        return buffer

def looks_like_html(s):
        """
        :type s: str
        :rtype: bool
        """

        # must have a close tag or an entity reference to qualify
        if not (re.search(r"</(\w+)>", s) or re.search(r"&#?\w+;", s)):
            return False

        # all tags must be in a restricted subset of valid HTML tags
        if any(
            t
            for t in re.findall(r"</?(\w+)", s)
            if t.lower() not in HTMLSanitizer.acceptable_elements
        ):
            return False

        # all entities must have been defined as valid HTML entities
        if any(
            e for e in re.findall(r"&(\w+);", s) if e not in html.entities.entitydefs
        ):
            return False

        return True

def _parse_date_nate(dateString):
    """Parse a string according to the Nate 8-bit date format"""
    m = _korean_nate_date_re.match(dateString)
    if not m:
        return
    hour = int(m.group(5))
    ampm = m.group(4)
    if ampm == _korean_pm:
        hour += 12
    hour = str(hour)
    if len(hour) == 1:
        hour = "0" + hour
    w3dtfdate = (
        "%(year)s-%(month)s-%(day)sT%(hour)s:%(minute)s:%(second)s%(zonediff)s"
        % {
            "year": m.group(1),
            "month": m.group(2),
            "day": m.group(3),
            "hour": hour,
            "minute": m.group(6),
            "second": m.group(7),
            "zonediff": "+09:00",
        }
    )
    return _parse_date_w3dtf(w3dtfdate)

def _start_link(self, attrs_d):
        attrs_d.setdefault("rel", "alternate")
        if attrs_d["rel"] == "self":
            attrs_d.setdefault("type", "application/atom+xml")
        else:
            attrs_d.setdefault("type", "text/html")
        context = self._get_context()
        attrs_d = self._enforce_href(attrs_d)
        if "href" in attrs_d:
            attrs_d["href"] = self.resolve_uri(attrs_d["href"])
        if (
            attrs_d.get("rel") == "alternate"
            and self.map_content_type(attrs_d.get("type")) in self.html_types
        ):
            self.isentrylink = 1
        expecting_text = self.infeed or self.inentry or self.insource
        context.setdefault("links", [])
        if not (self.inentry and self.inimage):
            context["links"].append(FeedParserDict(attrs_d))
        if "href" in attrs_d:
            if self.isentrylink:
                context["link"] = attrs_d["href"]
        else:
            self.push("link", expecting_text)

